let main = document.querySelector(".add-input")

let song1 = {
  artist: "Olivia Rodrigo",
  songName: "purple",
  image: "data:image/webp;base64,",
  url: "https://open.spotify.com/track/4XYCWx98N3h7Y4FtDFmpd5?si=c26aec17996c4b95"
}

console.log(song1);
let song2 = {
  artist: "Luis Fonsi",
  songName: "Despacito",
  image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQY6uTXTeG-WSTGVCAVvb9f-Jg4m8cCzgVuC1g6m2LqrA&s=10",
  url: "https://open.spotify.com/track/6habFhsOp2NvshLv26DqMb"
}

let song3 = {
  artist: "Lil nas X",
  songName: "Old Town Road",
  image: "https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcRyq2Aja2EFlcpd5pVMDwEPv9jon1ClLaFcHlsLEYA9gQ&s=10",
  url: "https://open.spotify.com/album/38kpkGLuPr1nNfD3iEyOlJ"
}

let song4 = {
  artist: "James Lord Pierpont",
  songName: "Jingle Bells",
  image: "data:image/jpeg;base64,",
  url: "https://open.spotify.com/artist/7iGYJRh51EK8Msev8akMZX"
}

let songArray = [song1, song2, song3, song4];
let body = document.querySelector(".display");

songArray.forEach(function(song){
  let div = document.createElement("div");
  div.innerHTML = `<div class="height"><a target="_blank" href="${song.url}"> <h2> ${song.songName} </h2> <br> <p class="name">${song.artist}</p>  <img src="${song.image}"></div> </a>`;
    body.appendChild(div);

});

main.addEventListener("click", function(){
body.innerHTML = "";
let songInput = document.querySelector(".title");
let artistInput = document.querySelector(".artist");
let imageInput = document.querySelector(".image");
let linkInput = document.querySelector(".link");
 

let s = songInput.value;
let a = artistInput.value;
let l = imageInput.value;
let u = linkInput.value;

let song = {
  artist: a,
  songName: s,
  image: l,
  url: u
};

songArray.push(song);



songArray.forEach(function(song){
  let div = document.createElement("div");
  div.innerHTML = `<div class="height"><a target="_blank" href="${song.url}"> <h2> ${song.songName} </h2> <br> <p class="name">${song.artist}</p>  <img src="${song.image}"></div> </a>`;
  body.appendChild(div);
});
});
